#include<bits/stdc++.h>
using namespace std;
struct node{
	long long t,a;
};
queue<node>q;
int tong[100005];
int main()
{
//	freopen("port.in","r",stdin);
//	freopen("port.out","w",stdout);
	int t;
	cin>>t;
	int cnt=0;
	while(t--){
		int n,m;
		scanf("%d%d",&n,&m);
		for(int i=0;i<m;i++){
			int b;
			scanf("%d",&b);
			node x;
			x.a=b;
			x.t=n;
			if(tong[b]==0)cnt++;
			tong[b]++;
			q.push(x);
		}
		while(q.size()){
//			cout<<q.back().t-q.front().t<<endl;
			if(86400>q.back().t-q.front().t){
				break;
			}
			if(tong[q.front().a]==1)cnt--;
			tong[q.front().a]--;
			q.pop();
//			cout<<q.front().a<<" "<<tong[q.front().a]<<"\n";
		}
		printf("%d\n",cnt);
	}
}
